[['AAPL', 'MSFT'], ['Signal(\n                timestamp=datetime(2024, 6, 15, tzinfo=timezone.utc),\n                symbol="AAPL', 'target_position_pct=0.4,  # 40% of NAV\n                model_version="v1', 'Signal(\n                timestamp=datetime(2024, 6, 15, tzinfo=timezone.utc),\n                symbol="MSFT', 'target_position_pct=0.3,  # 30% of NAV\n                model_version="v1', 'Mock positions and prices to simulate high NAV\n        loop._position_writer.positions = {}\n        loop._get_current_prices = MagicMock(return_value={"AAPL', 150.0, 'MSFT": 300.0})\n        loop._compute_nav = MagicMock(return_value=100000.0)  # $100K NAV\n        \n        # Mock risk engine to return rejection for high exposure\n        with patch("research.execution.paper_trading.project_weights_full', 'as mock_project:\n            mock_project.return_value = RiskResult(\n                weights=np.array([0.4, 0.3]),  # Same weights (no adjustment)\n                decisions=[\n                    MagicMock(\n                        rule_id="max_gross_exposure', 'decision=Decision.REJECT,\n                        details={"total', 0.7, 'limit', 0.5], ['MagicMock(\n                        order=OrderRequest(\n                            symbol="AAPL', 'side=OrderSide.BUY,\n                            notional=40000.0,  # 40% of $100K\n                        ),\n                        signal=signals[0],\n                        reason="order_generated', 'Process signals\n                loop._process_signals()\n                \n                # Verify risk engine was called\n                mock_project.assert_called_once()\n                \n                # Verify risk writer logged the decision\n                loop._risk_writer.log_result.assert_called_once()\n                \n                # Verify order was not submitted due to risk rejection\n                mock_broker.submit_order.assert_not_called()\n\n    @patch("research.execution.paper_trading.load_production_risk_config")\n    @patch("research.execution.paper_trading.AlpacaBrokerAdapter")\n    @patch("research.execution.paper_trading.AlpacaBrokerConfig.from_env', 'def test_risk_decisions_logged_to_table(self, mock_from_env, mock_broker_cls, mock_risk, config):\n        "', 'Unit test showing risk decisions are written to the risk_decisions table."', '\n        mock_risk.return_value = RiskConfig()\n        mock_from_env.return_value = MagicMock()\n        mock_broker = MagicMock()\n        mock_broker_cls.return_value = mock_broker\n\n        loop = PaperTradingLoop(config)\n        loop._risk_writer = MagicMock()\n\n        # Create a signal\n        signals = [\n            Signal(\n                timestamp=datetime(2024, 6, 15, tzinfo=timezone.utc),\n                symbol="AAPL', 'target_position_pct=0.1,\n                model_version="v1', 'loop._position_writer.positions = {}\n        loop._get_current_prices = MagicMock(return_value={"AAPL": 150.0})\n        loop._compute_nav = MagicMock(return_value=100000.0)\n        \n        # Mock risk engine to return some decisions\n        with patch("research.execution.paper_trading.project_weights_full', 'as mock_project:\n            mock_project.return_value = RiskResult(\n                weights=np.array([0.1]),\n                decisions=[\n                    MagicMock(\n                        rule_id="max_symbol_weight', 'decision=Decision.PASS,\n                        details={"limit', 0.2], ['MagicMock(\n                        order=OrderRequest(\n                            symbol="AAPL', 'side=OrderSide.BUY,\n                            notional=10000.0,\n                        ),\n                        signal=signals[0],\n                        reason="order_generated', 'Process signals\n                loop._process_signals()\n                \n                # Verify risk decisions were logged\n                loop._risk_writer.log_result.assert_called_once()']]